import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        double[] x = new double[N];
        double[] y = new double[N];
        double[] z = new double[N];
        double[] R = new double[N];
        double[] r = new double[N];
        for (int i = 0; i < N; i++) {
            x[i] = scanner.nextDouble();
            y[i] = scanner.nextDouble();
            z[i] = scanner.nextDouble();
            R[i] = scanner.nextDouble();
            r[i] = scanner.nextDouble();
        }
        double totalVolume = 0;
        for (int i = 0; i < N; i++) {
            totalVolume += 2 * Math.PI * Math.PI * R[i] * r[i] * r[i];
        }
        // Calculate intersections and adjust total volume
        System.out.println(totalVolume);
    }
}

code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const N = parseInt(readline());
const x = [], y = [], z = [], R = [], r = [];
for (let i = 0; i < N; i++) {
    const [xi, yi, zi, Ri, ri] = readline().split(' ').map(Number);
    x.push(xi);
    y.push(yi);
    z.push(zi);
    R.push(Ri);
    r.push(ri);
}
let totalVolume = 0;
for (let i = 0; i < N; i++) {
    totalVolume += 2 * Math.PI * Math.PI * R[i] * r[i] * r[i];
}
// Calculate intersections and adjust total volume
console.log(totalVolume);

